fn open_input(path: &PathBuf, _try_decompress: bool) -> Result<Box<dyn BufRead>> {
    let f = File::open(path)
        .map_err(|e| anyhow!("{}", e))?;
    let ext_is_gz = path
        .extension()
        .and_then(|e| e.to_str())
        .map(|e| e.eq_ignore_ascii_case("gz") || e.eq_ignore_ascii_case("bgz"))
        .unwrap_or(false);
    if _try_decompress && ext_is_gz {
        // gzip
        let dec = flate2::read::MultiGzDecoder::new(f);
        Ok(Box::new(BufReader::new(dec)))
    } else {
        Ok(Box::new(BufReader::new(f)))
    }
}

