fn parse_field_ranges(s: &str) -> Result<Vec<FieldRange>> {
    let mut ranges = Vec::new();
    for part in s.split(',') {
        if let Some(dash_idx) = part.find('-') {
            let (a, b) = (&part[..dash_idx], &part[dash_idx + 1..]);
            if !a.is_empty() && !is_all_digits(a) {
                return Err(anyhow!("Failed to parse field: {}", part));
            }
            if !b.is_empty() && !is_all_digits(b) {
                return Err(anyhow!("Failed to parse field: {}", part));
            }
            let start: usize = if a.is_empty() {
                1
            } else {
                a.parse().map_err(|_| anyhow!("Failed to parse field: {}", part))?
            };
            let end: usize = if b.is_empty() {
                usize::MAX
            } else {
                b.parse().map_err(|_| anyhow!("Failed to parse field: {}", part))?
            };
            if start == 0 || (end != usize::MAX && end == 0) {
                return Err(anyhow!("Fields and positions are numbered from 1: 0"));
            }
            if end != usize::MAX && end < start {
                return Err(anyhow!("High end of range less than low end of range: {}", part));
            }
            ranges.push(FieldRange { start, end });
        } else {
            if !is_all_digits(part) {
                return Err(anyhow!("Failed to parse field: {}", part));
            }
            let v: usize = part.parse().map_err(|_| anyhow!("Failed to parse field: {}", part))?;
            if v == 0 {
                return Err(anyhow!("Fields and positions are numbered from 1: 0"));
            }
            ranges.push(FieldRange { start: v, end: v });
        }
    }
    Ok(ranges)
}

