// Combine -F (header-derived) and -f ranges.
// Heuristic: start with -f's ordered list. For each -F item (in CLI order),
// insert at the first position where the current list element's start col
// is strictly greater than the -F item's start col. If no such position,
// append. This matches single-F + multi-f cases.
let mut combined: Vec<FieldRange> = cfg.fields.clone();
for fh in &f_from_header {
    let target = fh.start;
    let pos = combined
        .iter()
        .position(|r| r.start > target)
        .unwrap_or(combined.len());
    combined.insert(pos, *fh);
}

